exercises.tests:
check('optimistic update stores prevValue and applies newValue', () => {
  const s0 = { items: { a: 'hello' }, pending: {} };
  const s1 = optimisticReducer(s0, { type: 'OPTIMISTIC_UPDATE', id: 'a', newValue: 'world', prevValue: 'hello' });
  expect(s1.items.a).toBe('world');
  expect(s1.pending.a).toBe('hello');
});
check('commit removes pending entry, keeps new value', () => {
  const s0 = { items: { a: 'world' }, pending: { a: 'hello' } };
  const s1 = optimisticReducer(s0, { type: 'COMMIT', id: 'a' });
  expect(s1.items.a).toBe('world');
  expect(s1.pending.a).toBe(undefined);
});
check('rollback reverts item to prevValue and clears pending', () => {
  const s0 = { items: { a: 'world' }, pending: { a: 'hello' } };
  const s1 = optimisticReducer(s0, { type: 'ROLLBACK', id: 'a' });
  expect(s1.items.a).toBe('hello');
  expect(s1.pending.a).toBe(undefined);
});

exercises.solution:
function optimisticReducer(state, action) {
  switch (action.type) {
    case 'OPTIMISTIC_UPDATE':
      return {
        items: { ...state.items, [action.id]: action.newValue },
        pending: { ...state.pending, [action.id]: action.prevValue }
      };
    case 'COMMIT': {
      const pending = { ...state.pending };
      delete pending[action.id];
      return { ...state, pending };
    }
    case 'ROLLBACK': {
      const pending = { ...state.pending };
      const prevValue = pending[action.id];
      delete pending[action.id];
      return {
        items: { ...state.items, [action.id]: prevValue },
        pending
      };
    }
    default:
      return state;
  }
}
